using ll = long long long;


int main() {
  int N;
  while (cin >> N) {
    vector<int> a(N), b(N);
    for (int i = 0; i < N; i++) {
      cin >> a[i];
    }
    for (int i = 0; i < N; i++) {
      cin >> b[i];
    }
    int dp[6][6][6];
    memset(dp, -1, sizeof(dp);
    function<bool(int, int> can = [&](int a, int b, int k) {
      int &res = dp[a][k];
      if (res != -1) {
        return res;
      }
      if (k == 0) {
        return res = (a == b);
      }
      return res = can(a, k - 1) || can(a % k, k - 1);
    };
