    for (int i = 0; i < N; i++) {
      ok &= can(a[i], b[i]);
    }
    if (!ok) {
      cout << -1 << endl;
      continue;
    }
    vector<int> ks;
    auto solve = [&](int a, int b, int k) {
      vector<bool> dp(a + 1, false);
      dp[a] = true;
      for (int k : ks) {
        vector<bool> ndp = dp;
        for (int i = 0; i <= a; i++) {
          if (dp[i]) {
            ndp[i % k] = true;
          }
        }
        dp = ndp;
      }
      for (int i = 0; i <= a; i++) {
        if (dp[i] && can(i, k - 1)) {
          return false;
        }
      }
      return true;
    };
    for (int k = 6; k >= 1; k--) {
      bool need = false;
      for (int i = 0; i < N; i++) {
